#![no_std]
#![no_main]
#![feature(alloc_error_handler)]
#![allow(dead_code)]

extern crate alloc;

#[macro_use]
extern crate bitflags;

use core::sync::atomic::Ordering;
use log::*;

#[path = "boards/mod.rs"]
mod board;
mod bpf;

// console 物理文件在 drivers/serial/ 下（与 ns16550a 同族），但 print!/println!
// 宏须在 crate 根 #[macro_use]，故经 #[path] 仍作为 crate::console 引入。
#[macro_use]
