/// trap 子系统已迁入 `arch/riscv64/trap/`（arch 内部，封装 CSR 细节）。
/// 此别名让 boot 路径的 `trap::init()`/`trap::enable_*_interrupt()` 仍可读。
use crate::arch::trap;

// entry.asm（boot 入口 `_start`/`_start_secondary`）已迁入 arch/riscv64/，
// 由 `arch/riscv64/mod.rs` 经 global_asm! 包含。link_app.S 由 build.rs 按
// kernel target 生成到 OUT_DIR，避免 RV/LA 来回构建时复用错误架构的用户 ELF。
core::arch::global_asm!(include_str!(concat!(env!("OUT_DIR"), "/link_app.S")));

fn clear_bss() {
    extern "C" {
        fn sbss();
        fn ebss();
    }
    unsafe {
        core::slice::from_raw_parts_mut(sbss as usize as *mut u8, ebss as usize - sbss as usize)
            .fill(0);
    }
}

/// Boot hart 入口 — 由 entry.asm `_start` 调用
#[no_mangle]
pub fn rust_main_boot(hartid: usize) -> ! {
    clear_bss();
    arch::early_init(hartid);
    runtime::banner::print_banner();
    runtime::logging::init();
    info!(
        "[kernel] StellarOS booting on boot hart {} (SMP={})...",
        hartid,
        config::SMP_COUNT
    );

    cpu::init_cpu(hartid);
    cpu::BOOT_HART_ID.store(hartid, Ordering::Release);

    let detected_cpus = cpu::detect_and_set_cpu_num(hartid, config::SMP_COUNT);
    info!("[kernel] Detected {} CPU(s).", detected_cpus);

    mm::init();
    trap::init();
    trap::enable_soft_interrupt();
    info!("[kernel] Trap handling initialized (boot hart).");

    net::init_loopback();
    if arch::has_platform_devices() {
        drivers::block::init();
        drivers::rng::init_device_entropy();
        // mount::init() 内部自动检测分区类型并初始化对应文件系统
        // （MBR 分区感知：FAT32/EXT2/EXT4 按需初始化）
        fs::mount::init();
        if arch::has_external_interrupts() {
            trap::enable_external_interrupt();
        }
        // mount 期间的同步 virtio block 读在完成时不主动清 ISR。外部中断使能后，
        // net::init() 的 VirtIO MMIO 扫描可能导致该 pending 中断被递交，若其时
        // handle_irq 未正确消费 ISR（try_lock 窗口 / event_idx 交互），后续 block
        // 读永久挂起。在 net::init 前做一次同步块读，在持 BLOCK_DEVICE 锁的上下文
        // 中安全消费所有 pending used-buffer 通知，消除此窗口。
        if arch::has_network_device() {
            crate::drivers::block::flush_pending();
            net::init_eth0();
        }
    } else {
        println!("[kernel] platform device init skipped");
        fs::mount::init_memory_root();
    }
    // 注册架构计数器为系统 clocksource（须在任何 get_time_ns 精确换算之前）。
    time::init_clocksource();
    // 建立 CLOCK_REALTIME 基准（必须在驱动初始化后、跑用户态前）。
    if arch::has_realtime_clock() {
        time::init_realtime();
    } else {
        time::init_realtime_fallback_2025();
    }
    info!("[kernel] Subsystems initialized.");

    trap::enable_timer_interrupt();
    time::set_next_trigger();
    task::add_initproc();

    cpu::BOOT_HART_READY.store(true, Ordering::Release);
    cpu::wait_all_harts_online();
    info!("[kernel] All harts ready, boot hart entering scheduler...");

    task::run_tasks();
}

/// Secondary hart 入口 — 由 entry.asm `_start_secondary` 调用
#[no_mangle]
pub fn rust_main_secondary(hartid: usize) -> ! {
    while !cpu::BOOT_HART_READY.load(Ordering::Acquire) {
        core::hint::spin_loop();
    }

    cpu::init_cpu(hartid);
    mm::activate_kernel_space();
    trap::init();
    trap::enable_soft_interrupt();
    trap::enable_timer_interrupt();
    time::set_next_trigger();
    if arch::has_external_interrupts() {
        trap::enable_external_interrupt();
    }

    cpu::mark_hart_online(hartid);
    info!("[kernel] Hart {} online, entering scheduler...", hartid);

    task::run_tasks();
}

OUTPUT_ARCH(riscv)
ENTRY(_start)
BASE_ADDRESS = 0x80200000;

SECTIONS
{
    . = BASE_ADDRESS;
    skernel = .;

    stext = .;
    .text : {
        *(.text.entry)
        . = ALIGN(4K);
        strampoline = .;
        *(.text.trampoline);
        . = ALIGN(4K);
        *(.text .text.*)
    }

    . = ALIGN(4K);
    etext = .;
    srodata = .;
    .rodata : {
        *(.rodata .rodata.*)
        *(.srodata .srodata.*)
    }

    . = ALIGN(4K);
    erodata = .;
    sdata = .;
    .data : {
        *(.data .data.*)
        *(.sdata .sdata.*)
    }

    . = ALIGN(4K);
    edata = .;
    sbss_with_stack = .;
    .bss : {
        *(.bss.stack)
        sbss = .;
        *(.bss .bss.*)
        *(.sbss .sbss.*)
    }

    . = ALIGN(4K);
    ebss = .;
    ekernel = .;

    /DISCARD/ : {
        *(.eh_frame)
    }
}

//! 架构抽象层 / 硬件抽象层（HAL）。
//!
//! 高层代码只依赖 `crate::arch::*`，各架构在子模块（`riscv64/`、`loongarch64/`…）各自实现，
//! 由本文件按 `target_arch` 统一重导出。验收：高层文件**零** `#[cfg(target_arch)]` 与
//! `riscv::`/`sbi_rt::` 直接引用（M0 已达成）。
//!
//! # arch 接口契约（HAL boundary）
//!
//! 本文件用**显式 `pub use`（非 glob `*`）固化接口**：每个架构子模块**必须**导出下列全部
//! 符号，否则切到该架构时**编译失败**——以此强制 LoongArch（及将来 x86/arm）与 riscv 接口
//! 对齐，避免"起 LA 后才发现少接口"。新增架构 = 建 `arch/<arch>/`，实现下表全部符号，
//! 在下方加一段 `#[cfg] pub use <arch>::{ 同一组 }` 即可，高层零改动。
//!
//! | 组 | 符号 | 语义 |
//! |----|------|------|
//! | 控制台 | `console_putchar(usize)` / `console_getchar()->usize` | 串口/SBI 收发字符（无字符返回 `usize::MAX`） |
//! | 定时器 | `set_timer(deadline:usize)` / `get_time()->usize` / `clock_freq()->usize` | 设下次定时中断 / 读硬件单调计数 / 计数频率 |
//! | 关机   | `shutdown(failure:bool)->!` | 主动关机（评测要求） |
//! | SMP/CPU| `send_ipi(...)->ArchRet` / `hart_id()->usize` | 跨核中断（统一 `ArchRet` 返回）/ 当前 hartid |
//! | SMP 起核 | 子模块 `smp::start_secondary(hartid)->ArchRet` | 起次级核：RV=SBI HSM 投递 `_start_secondary`，LA=全核自启动仅 `LA_SMP_ENABLED` 时计数；次级核入口知识各自闭合（x86=INIT-SIPI、arm=PSCI CPU_ON 照填）|
//! | IPI    | 子模块 `ipi::{enable_local, clear_local, send_reschedule, send_ipi, handle}` | 本核使能/清 pending IPI / 单目标重调度 / 掩码广播 / IPI ISR 公共动作（clear+TLB shootdown+resched）|
//! | FP     | 子模块 `fpu::{init_local, save_user, restore_user}`（统一 `FloatContext`）| 每 hart 使能 FPU（boot 一次）+ 用户态 FP 上下文 lazy 存取：RV 走 trap.S dirty 位（存取契约 no-op），LA 走 save-on-leave（契约实做）；x86/arm 照硬件能力填 |
//! | 中断   | `irq_enabled()->bool` / `disable_irq()` / `enable_irq()` / `wait_for_interrupt()` | 本核中断开关 + idle |
//! | 地址空间 | `activate_pagetable(token:usize)` / `flush_tlb_all()` / `flush_tlb_page(va:usize)` | 切页表根+刷TLB / 全量刷TLB / 单 VA 精确失效（COW/lazy 单页变更用，x86=invlpg、arm=tlbi vae1）|
//! | ASID（feature=asid）| `ASID_BITS:u32` / `token_with_asid(token,asid)->usize` | asid 位宽（arch 拥有，RV satp 16/LA CSR.ASID 10）/ 把 asid 嵌入激活字（RV=satp[59:44]；LA=后续 PGDL+CSR）。通用分配策略见 `mm::asid`，flush_tlb_* 已天然失效所有 asid（shootdown 无需感知 asid）|
//! | syscall ABI | `decode_clone_args(arg2,arg3,arg4)` | 架构负责把 Linux clone 后三参解码为 `(parent_tidptr,tls,child_tidptr)` |
//! | seccomp ABI | `seccomp_audit_arch()` | Linux AUDIT_ARCH_* 常量，供 cBPF 读取 `seccomp_data.arch` |
//! | 用户 ABI 字符串 | `UTS_MACHINE` / `AT_PLATFORM` / `write_proc_cpuinfo()` | `uname(2)` machine 字段、ELF auxv `AT_PLATFORM` 与 `/proc/cpuinfo` 架构字段 |
//! | VirtIO | `probe_virtio_blk()` / `probe_virtio_net()` | 架构/平台负责枚举 MMIO 或 PCI transport，设备驱动负责业务逻辑 |
//! | trap 上下文定位 | `locate_trap_cx(memory_set, user_va, kstack_top)` / `uses_user_trap_cx()` | 为新任务定位/映射 trap context / 是否需要用户态 trap context 虚页 |
//! | 启动能力 | `early_init(hartid)` / `has_platform_devices()` / `has_external_interrupts()` / `has_network_device()` / `has_realtime_clock()` / `uses_identity_kernel_stack()` / `task_context_top(kstack_top)` | 架构早期初始化 / 当前 boot 是否可初始化块设备、外部中断、网络、RTC / task 内核栈是否走 identity 物理地址 / 初始切换 frame 顶部 |
//! | 陷入   | 类型 `TrapContext`；子模块 `trap::{init, trap_handler, trap_return, trap_from_kernel, enable_soft/timer/external_interrupt}` | 陷入上下文 + dispatch/trampoline/中断使能 |
//! | 上下文 | 子模块 `switch::{__switch, __switch_load_only, __switch_with_hook, __goto_idle, __save_run_hook_goto_idle}` | 内核栈上下文切换 |
//!
//! > `hart_id` 已纳入契约（原散在 cpu/mod.rs 读 tp）；FPU 每 hart 使能由 `cpu::enable_fpu`
//! > 迁入 `fpu::init_local`（与 FP 存取契约同模块内聚）。
//! > 仍特殊处理：`spin_lock.rs` 的 `mv ra` 仅 `lockdbg` feature 编译（非默认，不入契约）；
//! > linker 入口地址走 per-arch `linker.ld`。

#[cfg(target_arch = "riscv64")]
mod riscv64;
#[cfg(target_arch = "loongarch64")]
mod loongarch64;

/// 跨架构 SMP/IPI 调用统一返回类型。
///
/// 取代 RISC-V 早期直接把 `sbi_rt::SbiRet` 泄漏到 HAL 边界的做法——后者会让
/// LoongArch（自定义 IOCSR 返回）与将来 x86/arm 无法对齐同一接口。所有架构的
/// `hart_start` / `send_ipi` 统一返回本类型：`error == 0` 表示成功，`value` 为
/// 调用相关的返回值（HSM/SBI 语义透传）。
///
/// 设计取自两边优点：沿用 SBI `SbiRet` 的 `{error, value}` 双字段语义（高层
/// `detect_and_set_cpu_num` / `tlb_shootdown` 已按此读 `.error`/`.value`），同时
/// 用架构无关的纯数据结构消除对 `sbi_rt` 的类型依赖。
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct ArchRet {
    /// 错误码：0 = 成功；非 0 = 架构相关错误（RV 透传 SBI error，LA 用 -1）。
    pub error: isize,
    /// 返回值：调用相关（如 HSM 状态码），无意义时为 0。
    pub value: usize,
}

impl ArchRet {
    /// 成功（error=0, value=0）。
    pub const fn ok() -> Self {
        Self { error: 0, value: 0 }
    }

    /// 失败（error=-1, value=0）。
    pub const fn err() -> Self {
        Self { error: -1, value: 0 }
    }

    /// 是否成功。
    #[inline]
    pub fn is_ok(&self) -> bool {
        self.error == 0
    }
}

// ── arch 接口契约：每个架构必须导出以下全部符号（缺一即编译失败）──
