    activate_pagetable, flush_tlb_all, flush_tlb_page, locate_trap_cx, uses_user_trap_cx,
    // syscall ABI
    decode_clone_args, seccomp_audit_arch, write_proc_cpuinfo, AT_PLATFORM, UTS_MACHINE,
