//! RISC-V64 架构实现。
//!
//! 现状（M0 起步）：先把平台服务（SBI 封装：console/timer/shutdown/IPI/hart）
//! 收进本模块并经 `crate::arch::*` 暴露。trap/page_table/switch/context/entry
//! 等重耦合后续逐块迁入。

mod console;
mod cpu;
mod interrupt;
mod mm;
mod platform;
mod sbi;
mod virtio;
pub mod fpu;
pub mod ipi;
pub mod smp;
pub mod switch;
pub mod trap;

// boot 入口（`_start`/`_start_secondary`，调 rust_main_boot/secondary）。
core::arch::global_asm!(include_str!("entry.S"));

/// 控制台：经 SBI legacy console 提供；单独成模块以对齐 LoongArch UART console。
pub use console::{console_getchar, console_putchar};

/// CPU 杂项：hart id（读 tp）、FPU 使能（sstatus.FS）。
pub use cpu::hart_id;

/// 中断控制 + idle。高层锁原语（`SpinNoIrqLock`/`UPIntrFreeCell`）与 idle 循环依赖。
pub use interrupt::{disable_irq, enable_irq, irq_enabled, wait_for_interrupt};

/// 地址空间激活 + TLB 维护。高层 mm/cpu/syscall 切页表、刷 TLB 用。
pub use mm::{activate_pagetable, flush_tlb_all, flush_tlb_page};
#[cfg(feature = "asid")]
pub use mm::{token_with_asid, ASID_BITS};

/// 平台服务与启动能力：timer/shutdown/HSM/IPI 由 SBI 提供，能力开关在本模块统一声明。
pub use platform::{
    clock_freq, early_init, get_time, has_external_interrupts, has_network_device,
    has_platform_devices, has_realtime_clock, rtc_time_ns, set_timer, shutdown, task_context_top,
    uses_identity_kernel_stack,
};

/// 跨核 IPI 掩码广播（契约顶层符号 `arch::send_ipi`），实现在 `ipi` 子模块。
pub use ipi::send_ipi;

/// 平台 VirtIO transport 探测。设备驱动只消费统一 probe，不直接关心 MMIO/PCI 枚举。
pub use virtio::{probe_virtio_blk, probe_virtio_net, probe_virtio_rng};

/// 陷入上下文（寄存器布局与 `trap/trap.S` 偏移一致）。高层 task/signal 只见 `crate::arch::TrapContext`。
/// trap dispatch/trampoline/中断使能等仍在 `crate::arch::trap::*`（arch 内部，含 riscv:: CSR）。
pub use trap::TrapContext;

/// PTRACE_GETREGSET NT_PRSTATUS（RV64）：将 TrapContext 打包为 Linux user_regs_struct。
///
/// 布局：[pc(8B), x1..x31(31×8B)] = 32×8 = 256 字节
pub fn ptrace_get_nt_prstatus(
    cx: &TrapContext,
    token: usize,
    buf_ptr: usize,
    buf_len: usize,
) -> usize {
    use crate::mm::translated_refmut;
    let reg_size = core::mem::size_of::<usize>();
    let total = 32 * reg_size; // 256 bytes
    let to_write = total.min(buf_len);
    // [0] = pc
    if to_write >= reg_size {
        *translated_refmut(token, buf_ptr as *mut usize) = cx.sepc;
    }
    // [1..31] = x1..x31
    for i in 1..32usize {
        let off = i * reg_size;
        if off + reg_size > to_write {
            break;
        }
        *translated_refmut(token, (buf_ptr + off) as *mut usize) = cx.x[i];
    }
    to_write
}

/// PTRACE_SETREGSET NT_PRSTATUS（RV64）：从 buf 还原寄存器到 TrapContext。
pub fn ptrace_set_nt_prstatus(
    cx: &mut TrapContext,
    token: usize,
    buf_ptr: usize,
    buf_len: usize,
) {
    use crate::mm::translated_ref;
    let reg_size = core::mem::size_of::<usize>();
    if buf_len >= reg_size {
        cx.sepc = *translated_ref(token, buf_ptr as *const usize);
    }
    for i in 1..32usize {
        let off = i * reg_size;
        if off + reg_size > buf_len {
            break;
        }
        cx.x[i] = *translated_ref(token, (buf_ptr + off) as *const usize);
    }
}

pub const UTS_MACHINE: &[u8] = b"riscv64\0";
pub const AT_PLATFORM: &[u8] = b"riscv64\0";
pub const fn seccomp_audit_arch() -> u32 {
    0xc000_00f3
}

pub fn write_proc_cpuinfo(out: &mut alloc::string::String, cpu: usize) {
    use core::fmt::Write;

    let _ = writeln!(out, "processor\t: {}", cpu);
