pub fn locate_trap_cx(
    memory_set: &mut crate::mm::MemorySet,
    user_va: usize,
    _kstack_top: usize,
) -> Option<(crate::mm::PhysPageNum, usize, usize)> {
    use crate::mm::{MapPermission, VirtAddr};

    let va = VirtAddr::from(user_va);
    let ppn = if let Some(pte) = memory_set.translate(va.into()).filter(|pte| pte.is_valid()) {
        pte.ppn()
    } else {
        if !memory_set.try_insert_framed_area(
            user_va.into(),
            (user_va + crate::config::PAGE_SIZE).into(),
            MapPermission::R | MapPermission::W,
        ) {
            return None;
        }
        memory_set.translate(va.into())?.ppn()
    };
    let kptr = ppn.get_mut::<TrapContext>() as *mut TrapContext as usize;
    Some((ppn, kptr, user_va))
}

