/// 次级核 Rust 入口——由 `entry.S` 的 `.Lsecondary_proceed` 跳入（$a0=cpuid）。
///
/// QEMU loongarch64 virt 复位时所有 vCPU 都进 `_start`；次级核设好 DMW+栈后到此。
/// 安全门控：`LA_SMP_ENABLED=false` 时直接 idle 停泊（不起核、不耗电、零回归）。
/// 开启时：等 boot 核建好内核页表（`BOOT_HART_READY`），做本核 MMU/TLB 初始化，
/// 再进通用 `rust_main_secondary`（激活内核页表 + trap/timer/IPI + 上线 + 调度）。
#[no_mangle]
pub extern "C" fn la_secondary_entry(cpuid: usize) -> ! {
    if !ipi::LA_SMP_ENABLED {
        // 单核停泊：与历史 `.Lsecondary_park` 等价。先关本核中断（次级核未装异常
        // 向量，IE=1 时被中断打中会跳飞），再 idle 永久 halt，不偷宿主 CPU 时间。
        interrupt::disable_irq();
        loop {
            interrupt::wait_for_interrupt();
        }
    }
    // 等 boot 核完成 mm::init()（建好 KERNEL_SPACE），再碰任何页表相关 CSR。
    while !crate::cpu::BOOT_HART_READY.load(core::sync::atomic::Ordering::Acquire) {
        core::hint::spin_loop();
    }
    // 本核 MMU 初始化（per-hart CSR：TLBRENTRY/STLBPS/PWCL/PWCH + 开启分页模式）。
    // DMW0/DMW1 已在 entry.S 设好；此处补齐 TLB 重填与分页使能，等价 boot 核 early_init。
    mm::init_tlb_refill();
    mm::enable_paging_with_dmw();
    // 进通用次级核初始化（内部再激活内核页表、装 trap/timer/IPI、mark_online、run_tasks）。
    crate::rust_main_secondary(cpuid)
}
