/// PTRACE_GETREGSET NT_PRSTATUS（LA64）：将 TrapContext 打包为 Linux user_pt_regs。
///
/// 布局：[r0..r31(32×8B), era(8B)] = 33×8 = 264 字节（追加 badv/orig_a0 后实际 280B，
/// 此处只填有用部分，多余补 0）。
pub fn ptrace_get_nt_prstatus(
    cx: &TrapContext,
    token: usize,
    buf_ptr: usize,
    buf_len: usize,
) -> usize {
    use crate::mm::translated_refmut;
    let reg_size = core::mem::size_of::<usize>();
    let total = 35 * reg_size; // 280 bytes (regs[32] + era + badv + orig_a0)
    let to_write = total.min(buf_len);
    // r0..r31
    for i in 0..32usize {
        let off = i * reg_size;
        if off + reg_size > to_write {
            break;
        }
        *translated_refmut(token, (buf_ptr + off) as *mut usize) = cx.r[i];
    }
    // era (csr_era) at offset 32
    let era_off = 32 * reg_size;
    if era_off + reg_size <= to_write {
        *translated_refmut(token, (buf_ptr + era_off) as *mut usize) = cx.era;
    }
    // badv, orig_a0 remain 0 (already cleared by caller's iovec)
    to_write
}

/// PTRACE_SETREGSET NT_PRSTATUS（LA64）：从 buf 还原寄存器到 TrapContext。
pub fn ptrace_set_nt_prstatus(
    cx: &mut TrapContext,
    token: usize,
    buf_ptr: usize,
    buf_len: usize,
) {
    use crate::mm::translated_ref;
    let reg_size = core::mem::size_of::<usize>();
    for i in 0..32usize {
        let off = i * reg_size;
        if off + reg_size > buf_len {
            break;
        }
        cx.r[i] = *translated_ref(token, (buf_ptr + off) as *const usize);
    }
    let era_off = 32 * reg_size;
    if era_off + reg_size <= buf_len {
        cx.era = *translated_ref(token, (buf_ptr + era_off) as *const usize);
    }
}

