#[derive(Clone)]
pub struct VmMeta {
    // 堆管理
    pub heap_bottom: usize,
    pub program_brk: usize,
    // 内存映射区域
    pub mmap_areas: BTreeMap<usize, MmapArea>,
    // brk 堆管理
    pub brk: usize,
    pub brk_start: usize,
    // thread trap context slot 分配器（仅 CLONE_VM 线程使用）
    pub trap_cx_next_slot: usize,
    pub trap_cx_free_slots: Vec<usize>,
    /// mmap 自动分配的 bump 指针（单调递增，从 MMAP_BASE 起）。
    /// CLONE_VM 线程共享同一 VmMeta → 共享 mmap_top → 在 vm 锁内串行 bump，
    /// 绝不复用地址。旧实现靠 mmap_areas 记账找空隙，但 munmap 只按精确 key
    /// 移除，glibc arena 的 mmap-大块+munmap-头尾对齐 dance 会让记账与真实映射
    /// 失配 → 两线程 arena 分配到同一地址重叠 → "double free in tcache"。
    pub mmap_top: usize,
    /// mseal(462) 封印区间 [(start, end))。封印后 munmap/mprotect/mremap/
    /// mmap(MAP_FIXED 覆盖)/破坏性 madvise 一律 EPERM。VmMeta 随 fork Clone
    /// → 子进程继承封印；exec 新建 VmMeta → 封印随旧地址空间消亡（Linux 同语义）。
    pub sealed_ranges: Vec<(usize, usize)>,
}

impl VmMeta {
    pub fn new(heap_bottom: usize) -> Self {
        Self {
            heap_bottom,
            program_brk: heap_bottom,
            mmap_areas: BTreeMap::new(),
            brk: 0,
            brk_start: 0,
            trap_cx_next_slot: 0,
            trap_cx_free_slots: Vec::new(),
            mmap_top: 0,
            sealed_ranges: Vec::new(),
        }
    }

    /// 登记封印区间（页对齐由调用方保证）；相邻/重叠区间合并，防 Vec 无限膨胀。
    pub fn seal_range(&mut self, start: usize, end: usize) {
        let mut new_start = start;
        let mut new_end = end;
        self.sealed_ranges.retain(|&(s, e)| {
            if s <= new_end && new_start <= e {
                new_start = new_start.min(s);
                new_end = new_end.max(e);
                false
            } else {
                true
            }
        });
        self.sealed_ranges.push((new_start, new_end));
    }

    /// 查询 [start, start+len) 是否与任一封印区间相交。
    pub fn range_sealed(&self, start: usize, len: usize) -> bool {
        let end = start.saturating_add(len);
        self.sealed_ranges
            .iter()
            .any(|&(s, e)| start < e && s < end)
    }

    pub fn file_mmap_eof_fault(&self, addr: usize) -> bool {
        for area in self.mmap_areas.values() {
            if area.fd < 0 {
                continue;
            }
            let area_end = area.start.saturating_add(area.len);
            if addr < area.start || addr >= area_end {
                continue;
            }
            let valid_len = area
                .file_len
                .min(area.len)
                .saturating_add(crate::config::PAGE_SIZE - 1)
                & !(crate::config::PAGE_SIZE - 1);
            let valid_end = area.start.saturating_add(valid_len.min(area.len));
            return addr >= valid_end;
        }
        false
    }

    pub fn alloc_trap_cx_slot(&mut self) -> usize {
        if let Some(s) = self.trap_cx_free_slots.pop() {
            s
        } else {
            let s = self.trap_cx_next_slot;
            self.trap_cx_next_slot += 1;
            s
        }
    }

    pub fn free_trap_cx_slot(&mut self, slot: usize) {
        // [DIAG] 检测 slot 双重释放：会导致两个存活线程拿到同一 trap_cx VA →
        // 一方退出时 remove_area 解除另一方的 trap_cx 映射 → __restore 写
        // trap_cx 触发 StorePageFault → 陷阱风暴。
        if self.trap_cx_free_slots.contains(&slot) {
            panic!(
                "[BUG] trap_cx slot {} double-freed (next_slot={}, free={:?})",
                slot, self.trap_cx_next_slot, self.trap_cx_free_slots
            );
        }
        self.trap_cx_free_slots.push(slot);
    }
}

