fn update_current_sched_entity_for_requeue(inner: &mut TaskInner) {
    let now_ns = crate::time::get_time_ns() as u64;
    inner.sched_entity.update_vruntime(now_ns);
    let (new_deadline, _) = crate::sched::EevdfScheduler::check_deadline(&inner.sched_entity);
    inner.sched_entity.deadline = new_deadline;
}

pub fn suspend_current_and_run_next() {
    // SMP race fix: 必须先 publish kstack_sp（在 __switch_with_hook 内）再
    // sched_add_task。否则远端 hart 可能从队列里 fetch 这个 task，按 stale
    // 的 kstack_sp __switch 进去，恢复出错乱的 ra/s 寄存器，跳到非法地址。
    // schedule_with_hook 保证：
    //   1) __switch_with_hook 先 sd sp -> task.kstack_sp（publish）
    //   2) 再调 hook（这里 push 进 sched 队列）
    //   3) 最后 ld 下个 task 的 sp 切走
    // hook 执行时 task.kstack_sp 已是 fresh 值，远端 fetch 必然安全。
    let task = take_current_task().unwrap();
    let kstack_sp_ptr = task.kstack_sp.as_ptr();
    {
        let mut task_inner = task.inner.exclusive_access();
        task_inner.task_status = TaskStatus::Ready;
        update_current_sched_entity_for_requeue(&mut task_inner);
    }
    // 两阶段入队（SMP 关键）：
    //   1) hook 内（已 publish fresh kstack_sp，但仍在本任务 kstack 上）只把 Arc
    //      移交给 per-cpu pending_reenqueue —— 此刻任务**尚未**进入就绪队列，
    //      其它 hart 还 fetch 不到它。
    //   2) idle 循环在 `mv sp, idle_top` 切回 idle 栈后，才 sched_add_task 真正入队。
    // 这样「任务变为可 fetch」与「本 hart 仍在该 kstack 上执行」不再重叠，
    // 消除 SMP=4 下两核同栈并发导致的栈/堆损坏。
    // （旧实现在 hook 内直接 sched_add_task：publish 解决了 stale-sp，但任务入队后
    //   本 hart 还要执行 hook 返回 + `mv sp,a1` 等数条指令才切走，这段窗口内远端
    //   已可 fetch 并在同一 kstack 上跑 → 损坏。）
    schedule_with_hook(kstack_sp_ptr, move || {
        crate::cpu::current_cpu().pending_reenqueue = Some(task);
    });
}

/// 将当前任务置为 Blocked 并让出 CPU。
///
/// 返回值：
/// - 非 null：正常阻塞路径，调用方需用返回的 kstack_sp_ptr 调用 schedule()。
/// - null：wakeup_pending 路径，内部已通过 schedule_with_hook 完成一次调度循环，
///   调用方不得再调 schedule()，直接返回让上层重新检查条件即可。

/// 内部：在持有 task.inner 锁的临界区内决定 Blocked 还是消费 wakeup_pending。
/// 返回 (kstack_sp_ptr, requeue_task) 二元组：
/// - 若 wakeup_pending 已置位：状态转为 Ready，返回 Some(task)，调用方负责用
///   schedule_with_hook 在 publish 后再 sched_add_task。
/// - 否则：状态转 Blocked，返回 None。调用方必须保证 task 已在某个 wait_queue
///   中（否则 Arc 唯一引用消失，task 会被 drop）。
fn prepare_block_current() -> (*mut usize, Option<Arc<Task>>) {
    let task = take_current_task().unwrap();
    let kstack_sp_ptr = task.kstack_sp.as_ptr();
    scheduler::sched_task_sleeping(&task);
    let mut task_inner = task.inner.exclusive_access();
    if task_inner.wakeup_pending {
        task_inner.wakeup_pending = false;
        task_inner.task_status = TaskStatus::Ready;
        update_current_sched_entity_for_requeue(&mut task_inner);
        drop(task_inner);
        return (kstack_sp_ptr, Some(task));
    }
    task_inner.task_status = TaskStatus::Blocked;
    drop(task_inner);
    drop(task);
    (kstack_sp_ptr, None)
}

/// 兼容旧 API：仅做状态翻转，**不入队**。调用方必须自行处理 requeue 逻辑
/// （或保证 task 已在 wait_queue 中），否则 wakeup_pending 路径会丢任务。
///
/// 优先使用 `block_current_and_run_next` —— 它正确处理 wakeup_pending +
/// publish-then-enqueue race。
pub fn block_current_task() -> *mut usize {
    let (kstack_sp_ptr, requeue) = prepare_block_current();
    if let Some(task) = requeue {
        // 退化为 SMP-不安全的旧行为：直接 enqueue（publish-after-enqueue
        // 会让远端 hart 用 stale sp __switch）。仅留给已知不依赖 wakeup_pending
        // 路径的调用方使用。新代码应换用 block_current_and_run_next。
        sched_add_task(task);
    }
    kstack_sp_ptr
}

pub fn block_current_and_run_next() {
    let task = take_current_task().unwrap();
    let kstack_sp_ptr = task.kstack_sp.as_ptr();
    scheduler::sched_task_sleeping(&task);
    let mut task_inner = task.inner.exclusive_access();
    if task_inner.wakeup_pending {
        // wakeup 早于 block：消费 pending，转 Ready 后走 publish-then-enqueue。
        task_inner.wakeup_pending = false;
        task_inner.task_status = TaskStatus::Ready;
        update_current_sched_entity_for_requeue(&mut task_inner);
        drop(task_inner);
        // 同 suspend：延迟到切回 idle 栈后再入队，避免任务可被远端 fetch 时
        // 本 hart 仍在它的 kstack 上 → 两核同栈并发损坏。见 pending_reenqueue。
        schedule_with_hook(kstack_sp_ptr, move || {
            crate::cpu::current_cpu().pending_reenqueue = Some(task);
        });
        return;
    }
