//! 全局任务管理器

use super::task::Task;
use crate::sync::SpinNoIrqLock;
use alloc::collections::BTreeMap;
use alloc::sync::{Arc, Weak};
use lazy_static::*;

lazy_static! {
    static ref TASK_REGISTRY: SpinNoIrqLock<BTreeMap<usize, Weak<Task>>> =
        SpinNoIrqLock::new(BTreeMap::new());
}

pub fn register_task(task: &Arc<Task>) {
    TASK_REGISTRY
        .exclusive_access()
        .insert(task.gettid(), Arc::downgrade(task));
}

pub fn unregister_task(tid: usize) {
    TASK_REGISTRY.exclusive_access().remove(&tid);
}

pub fn get_task(tid: usize) -> Option<Arc<Task>> {
    TASK_REGISTRY
        .exclusive_access()
        .get(&tid)
        .and_then(|w| w.upgrade())
}

/// 获取指定进程组中的所有任务
///
/// ⚠ 锁顺序:**绝不能**在持有 TASK_REGISTRY 锁时再去锁 task.inner。
/// exit_current_and_run_next 的路径是 inner → registry(持自身 inner 时调
/// get_task 锁 registry);若此处反向 registry → inner,两核分别走两条路径、
/// 目标同一个 task 时即 ABBA 死锁。又因 syscall 全程 SIE=0,死锁后 timer ISR
/// 也无法触发,整机永久 hang(SMP=4 lmbench lat_ctx 进程组 kill 与子进程 exit
/// 高频并发时必现)。故先在 registry 锁内只 upgrade 出 Arc,释放锁后再锁 inner
/// 过滤 pgid。
pub fn get_tasks_by_pgid(pgid: usize) -> alloc::vec::Vec<Arc<Task>> {
    let all: alloc::vec::Vec<Arc<Task>> = {
        let registry = TASK_REGISTRY.exclusive_access();
        registry.values().filter_map(|w| w.upgrade()).collect()
    };
    all.into_iter()
        .filter(|t| t.inner.exclusive_session(|inner| inner.pgid) == pgid)
        .collect()
}

/// 获取所有存活任务（用于 kill -1 广播）
pub fn get_all_tasks() -> alloc::vec::Vec<Arc<Task>> {
    let registry = TASK_REGISTRY.exclusive_access();
    registry.values().filter_map(|w| w.upgrade()).collect()
}

/// 获取存活任务数量
pub fn task_count() -> usize {
    let registry = TASK_REGISTRY.exclusive_access();
    registry.values().filter_map(|w| w.upgrade()).count()
}

