/// Base address where the dynamic interpreter (ld.so) is loaded.
const DL_INTERP_BASE: usize = 0x4000_0000;
/// Base address for PIE main binaries (ET_DYN executables).
const MAIN_PIE_BASE: usize = 0x10_0000;

/// Information extracted from the ELF load, used to build the auxiliary vector (auxv).
