    /// Main binary's entry point (AT_ENTRY), load_base already applied.
    pub at_entry: usize,
    /// Interpreter load base (AT_BASE); 0 for statically-linked binaries.
    pub at_base: usize,
    /// Load offset applied to the main binary (0 for non-PIE, MAIN_PIE_BASE for ET_DYN).
    pub load_base: usize,
}

/// Resolve an interpreter path from PT_INTERP to an absolute path in our VFS.
///
/// Linux embeds the interpreter path verbatim (e.g. `/lib/ld-linux-riscv64-lp64d.so.1`),
/// but our fs.img keeps the glibc dynamic linker under `/glibc/lib/` and the musl one
/// under `/musl/lib/`.  Try the path as-is first; if not found, search the known lib
/// directories by basename.
fn resolve_interp_path(path: &str) -> Option<String> {
    // Fast path: path exists verbatim in VFS
    if let Some((fs, rel)) = MOUNT_TABLE.lookup(path) {
        if fs.open(&rel, 0).is_ok() {
            return Some(path.into());
        }
    }
    // Slow path: try known lib directories using the basename
    let basename = path.rsplit('/').next().unwrap_or(path);
    let candidates = [
        alloc::format!("/glibc/lib/{}", basename),
        alloc::format!("/musl/lib/{}", basename),
        // musl's combined libc+interp is named libc.so but the interp path may differ
        String::from("/musl/lib/libc.so"),
    ];
    for candidate in &candidates {
        if let Some((fs, rel)) = MOUNT_TABLE.lookup(candidate) {
            if fs.open(&rel, 0).is_ok() {
                log::debug!("[dynld] remapped interp {} → {}", path, candidate);
                return Some(candidate.clone());
            }
        }
    }
    log::warn!("[dynld] interpreter not found: {}", path);
    None
}

/// Read the interpreter ELF from VFS, map its PT_LOAD segments at `DL_INTERP_BASE`,
/// and return `(entry_point, at_base)`.
/// 返回 `Some((entry, base))`；解析/打开失败回退静态 `Some((0,0))`；
/// 帧耗尽 OOM 或解释器 ELF 损坏返回 `None`（让 from_elf→exec ENOMEM，内核不 panic）。
fn load_interp(memory_set: &mut MemorySet, interp_path: &str) -> Option<(usize, usize)> {
    let resolved = match resolve_interp_path(interp_path) {
        Some(p) => p,
        None => {
            log::error!(
                "[dynld] cannot resolve interpreter '{}', falling back to static entry",
                interp_path
            );
            return Some((0, 0));
        }
    };
    let (fs, rel) = MOUNT_TABLE.lookup(&resolved).unwrap();
    let node = match fs.open(&rel, 0) {
        Ok(n) => n,
        Err(e) => {
            log::error!("[dynld] open interpreter '{}' failed: {}", resolved, e);
            return Some((0, 0));
        }
    };
    let data = node.read_all();
    let entry = MemorySet::map_elf_at(memory_set, &data, DL_INTERP_BASE)?;
    // musl ld.so reads its own ELF header at AT_BASE to find the dynamic section.
    // If the interpreter's first PT_LOAD has p_vaddr > 0, the ELF header (at vaddr 0
    // relative to base) won't be covered by any LOAD segment → SIGSEGV when ld.so
    // dereferences pointers from its header.  Map one page of headers at the base.
    let base_va: VirtAddr = DL_INTERP_BASE.into();
    if !memory_set.areas.iter().any(|a| {
        a.vpn_range.get_start() <= base_va.floor() && a.vpn_range.get_end() > base_va.floor()
    }) {
        let copy_len = core::cmp::min(crate::config::PAGE_SIZE, data.len());
        if !memory_set.try_push_with_offset(
            MapArea::new(
                base_va,
                (DL_INTERP_BASE + copy_len).into(),
                MapType::Framed,
                MapPermission::U | MapPermission::R,
            ),
            &data[..copy_len],
            0,
        ) {
            log::warn!("[dynld] OOM mapping interp header page");
            return None;
        }
    }
    // LoongArch：官方 musl 工具链把若干 sched_* 编译成 ENOSYS 用户态桩，
    // 在用户态即失败、syscall 不进内核（cyclictest check_privs 整组丢分）。
    // 加载 musl ld（即 libc）后按符号表定位这些桩并改写为真正发 syscall。
    #[cfg(target_arch = "loongarch64")]
    patch_la_musl_sched_stubs(memory_set, &data, DL_INTERP_BASE);
    log::info!(
        "[dynld] loaded interpreter '{}' at base {:#x}, entry {:#x}",
        resolved,
        DL_INTERP_BASE,
        entry
    );
    Some((entry, DL_INTERP_BASE))
}

