    /// 高层语义位，由 `PageTableEntry::{new,flags}` 负责编解码到 LA PTE。
    pub struct PTEFlags: u16 {
        const V = 1 << 0;
        const R = 1 << 1;
        const W = 1 << 2;
        const X = 1 << 3;
        const U = 1 << 4;
        const G = 1 << 5;
        const A = 1 << 6;
        const D = 1 << 7;
        /// Copy-On-Write 标记（RSW bit 8）
        const COW = 1 << 8;
    }
}

