    pub const V: usize = 1 << 0;
    pub const D: usize = 1 << 1;
    pub const PLV3: usize = 3 << 2;
    pub const MAT_CC: usize = 1 << 4;
    pub const G: usize = 1 << 6;
    pub const P: usize = 1 << 7;
    pub const W: usize = 1 << 8;
    pub const COW: usize = 1 << 9;
    pub const NR: usize = 1 << (usize::BITS - 3);
    pub const NX: usize = 1 << (usize::BITS - 2);
