    pub fn encode_flags(flags: PTEFlags) -> usize {
        let mut bits = 0usize;
        if flags.contains(PTEFlags::V) {
            bits |= V | MAT_CC;
        }
        if flags.intersects(PTEFlags::R | PTEFlags::W | PTEFlags::X | PTEFlags::U) {
            bits |= P;
        }
        if flags.contains(PTEFlags::W) {
            bits |= W | D;
        }
        if !flags.contains(PTEFlags::R) {
            bits |= NR;
        }
        if !flags.contains(PTEFlags::X) {
            bits |= NX;
        }
        if flags.contains(PTEFlags::U) {
            bits |= PLV3;
        }
        if flags.contains(PTEFlags::G) {
            bits |= G;
        }
        if flags.contains(PTEFlags::COW) {
            bits |= COW;
        }
        bits
    }

    pub fn decode_flags(bits: usize) -> PTEFlags {
        if bits & V == 0 {
            return PTEFlags::empty();
        }
        let mut flags = PTEFlags::V;
        if bits & NR == 0 {
            flags |= PTEFlags::R;
        }
        if bits & W != 0 {
            flags |= PTEFlags::W;
        }
        if bits & NX == 0 {
            flags |= PTEFlags::X;
        }
        if bits & PLV3 == PLV3 {
            flags |= PTEFlags::U;
        }
        if bits & G != 0 {
            flags |= PTEFlags::G;
        }
        if bits & D != 0 {
            flags |= PTEFlags::D;
        }
        if bits & COW != 0 {
            flags |= PTEFlags::COW;
        }
        flags
    }
}

impl PageTableEntry {
    pub fn new(ppn: PhysPageNum, flags: PTEFlags) -> Self {
        #[cfg(target_arch = "riscv64")]
        {
            return PageTableEntry {
                bits: ppn.0 << 10 | flags.bits as usize,
            };
        }
        #[cfg(target_arch = "loongarch64")]
        {
            return PageTableEntry {
                bits: ppn.0 << 12 | loongarch_pte::encode_flags(flags),
            };
        }
    }
    pub fn empty() -> Self {
        PageTableEntry { bits: 0 }
    }
    pub fn ppn(&self) -> PhysPageNum {
        #[cfg(target_arch = "riscv64")]
        {
            return (self.bits >> 10 & ((1usize << 44) - 1)).into();
        }
        #[cfg(target_arch = "loongarch64")]
        {
            return ((self.bits & loongarch_pte::PPN_MASK) >> 12).into();
        }
    }
    pub fn flags(&self) -> PTEFlags {
        #[cfg(target_arch = "riscv64")]
        // 取低 10 位（包括 RSW 的 2 位）
        {
            PTEFlags::from_bits_truncate((self.bits & 0x3FF) as u16)
        }
        #[cfg(target_arch = "loongarch64")]
        {
            loongarch_pte::decode_flags(self.bits)
        }
    }
    pub fn is_valid(&self) -> bool {
        (self.flags() & PTEFlags::V) != PTEFlags::empty()
    }
    pub fn readable(&self) -> bool {
        (self.flags() & PTEFlags::R) != PTEFlags::empty()
    }
    pub fn writable(&self) -> bool {
        (self.flags() & PTEFlags::W) != PTEFlags::empty()
    }
    pub fn executable(&self) -> bool {
        (self.flags() & PTEFlags::X) != PTEFlags::empty()
    }
}

