/// 调度策略常量（与 Linux 一致）
pub const SCHED_OTHER:    u32 = 0;
pub const SCHED_FIFO:     u32 = 1;
pub const SCHED_RR:       u32 = 2;
pub const SCHED_BATCH:    u32 = 3;
pub const SCHED_IDLE:     u32 = 5;
/// SCHED_DEADLINE: sys_sched_setscheduler 返回 EINVAL（未实现，阶段0处理）
pub const SCHED_DEADLINE: u32 = 6;

/// 优先级常量
pub const DEFAULT_PRIO:  u32 = 120; // nice 0 对应的优先级
pub const MAX_PRIO:      u32 = 139;
pub const MAX_RT_PRIO:   u32 = 99;
pub const MIN_RT_PRIO:   u32 = 1;
pub const MAX_NICE:      i32 = 19;
pub const MIN_NICE:      i32 = -20;

pub fn nice_to_priority(nice: i32) -> u32 { (nice + 120) as u32 }
pub fn priority_to_nice(prio: u32) -> i32 { prio as i32 - 120 }

/// 任务对 getpriority(2) 暴露的 nice 值（恒在 [MIN_NICE, MAX_NICE]）。
///
/// 我们把 RT 优先级 [1,99] 和 nice 派生优先级 [100,139] 挤在同一个 `sched_prio`
/// 字段里，因此只有 SCHED_OTHER/SCHED_BATCH 的 `sched_prio` 才能反算 nice；
/// RT/IDLE 等策略的 `sched_prio` 不是 nice 派生值（Linux 里它们另有 static_prio，
/// 默认 nice 0）。统一在此归一，避免 RT 任务被 getpriority 误报成越界 nice。
pub fn task_nice(policy: u32, sched_prio: u32) -> i32 {
    match policy {
        SCHED_OTHER | SCHED_BATCH => priority_to_nice(sched_prio).clamp(MIN_NICE, MAX_NICE),
        _ => 0,
    }
}

pub fn sched_entity_for_policy(policy: u32, prio: u32) -> SchedEntity {
    let nice = match policy {
        SCHED_OTHER | SCHED_BATCH => priority_to_nice(prio).clamp(MIN_NICE, MAX_NICE),
        _ => 0,
    };
    SchedEntity::new(nice)
}

//! EEVDF — Earliest Eligible Virtual Deadline First
//!
//! 参考 Linux 6.6 kernel/sched/fair.c + DragonOS kernel/src/sched/fair.rs。
//!
//! # 设计超越点（vs DragonOS / Linux）
//!
//! 1. **无 `force_mut()`**：DragonOS 大量使用 unsafe 内部可变性规避借用检查，
//!    我们用正确的 `&mut self` API 设计消除所有 unsafe。
//!
//! 2. **`lag clamping`**：Linux 6.6 的 `update_entity_lag` 对 lag 做 ±limit
//!    截断（防止长时间睡眠任务唤醒后 lag 无限大、立即抢占所有人）。
//!    DragonOS 实现了，我们完整移植并加注释说明数学意义。
//!
//! 3. **完整 Wakeup Preemption**：任务唤醒时检查能否立即抢占 curr。
//!    DragonOS 的 `check_preempt_currnet` 关键判断是 TODO，我们基于
//!    EEVDF 语义实现：woken 的 deadline < curr_remaining_deadline → 抢占。
//!
//! 4. **`reweight_entity`**：nice 变化时按比例调整 vruntime 和 deadline，
//!    保持任务在权重变化前后的 lag 不变（Linux reweight_eevdf 逻辑）。
//!
//! 5. **`yield_task`**：sched_yield() 调用时将 deadline 推进到 vruntime + ε，
//!    使任务排到 eligible 集合尾部，不饿死其他任务但也不完全放弃位置。
//!
//! 6. **`SchedClass` trait**：参考 Linux sched_ext（6.12）的可插拔调度器
//!    思想，定义 trait 接口，使 EEVDF/FIFO/未来自定义策略运行时可换。
//!    当前 EEVDF + FIFO 均实现此 trait；scheduler.rs 统一通过 trait 调度。
//!
//! # 数学速记
//! - V = min_vr + (Σw_i·(v_i-min_vr) + curr贡献) / (Σw_i + curr_w)
//! - eligible_i: v_i ≤ V，即 (v_i-min_vr)·Σw ≤ Σw·(v_j-min_vr)（整数不除）
//! - lag_i = w_i·(V - v_i)，在 [-limit, +limit] 截断
//! - pick: argmin{deadline_i | eligible_i}
//! - update_deadline: if v_i ≥ d_i → slice=base; d_i = v_i + calc_delta_fair(slice)

