/// 最小抢占粒度 0.75ms
const MIN_GRANULARITY_NS: u64 = 750_000;
/// 调度延迟 6ms（一个"周期"内所有任务至少跑一次）
const SCHED_LATENCY_NS: u64 = 6_000_000;
/// 周期最多容纳 SCHED_NR_LATENCY 个任务；超过后 period = nr × min_gran
const SCHED_NR_LATENCY: usize = 8;
/// nice=0 基准权重
pub const NICE_0_LOAD: u64 = 1024;

/// EEVDF 开关（true=EEVDF pick；false=旧 CFS pick 用于 A/B 对比回退）
pub const USE_EEVDF: bool = true;

/// Wakeup preemption 特性开关
