// ================================================================
//  LoadWeight
// ================================================================

pub struct LoadWeight {
    pub weight: u64,
    pub inv_weight: u64,
}

impl LoadWeight {
    pub const fn zero() -> Self { Self { weight: 0, inv_weight: 0 } }

    pub fn from_nice(nice: i32) -> Self {
        let idx = (nice + 20) as usize;
        Self {
            weight:     SCHED_PRIO_TO_WEIGHT[idx],
            inv_weight: SCHED_PRIO_TO_WMULT[idx],
        }
    }

    pub fn from_weight(weight: u64) -> Self {
        Self {
            weight,
            inv_weight: if weight == 0 { 0 } else { (1u64 << 32) / weight },
        }
    }

    /// 更新权重（reweight 时调用）
    pub fn update(&mut self, weight: u64) {
        self.weight = weight;
        self.inv_weight = if weight == 0 { 0 } else { (1u64 << 32) / weight };
    }
}

// ================================================================
//  定点运算（Linux __calc_delta 移植）
// ================================================================

/// delta_exec * weight / lw.weight（定点，不用浮点/硬件除法）
pub fn calc_delta(delta_exec: u64, weight: u64, lw: &LoadWeight) -> u64 {
    let mut fact = weight;
    let mut shift: i32 = WMULT_SHIFT;
    let fact_hi = (fact >> 32) as u32;
    if fact_hi != 0 {
        let fs = fact_hi.leading_zeros() as i32;
        shift -= fs;
        fact >>= fs;
    }
    fact = fact.wrapping_mul(lw.inv_weight);
    let fact_hi = (fact >> 32) as u32;
    if fact_hi != 0 {
        let fs = fact_hi.leading_zeros() as i32;
        shift -= fs;
        fact >>= fs;
    }
    if shift >= 0 { delta_exec.wrapping_mul(fact) >> shift }
    else          { delta_exec.wrapping_mul(fact) << (-shift) }
}

/// calc_delta_fair：虚拟时间增量 = delta_exec * NICE_0_LOAD / weight
#[inline]
pub fn calc_delta_fair(delta_exec: u64, load: &LoadWeight) -> u64 {
    if load.weight == NICE_0_LOAD { delta_exec }
    else { calc_delta(delta_exec, NICE_0_LOAD, load) }
}

// ================================================================
//  SchedEntity（嵌入 TaskInner）
// ================================================================

pub struct SchedEntity {
    /// 累计虚拟运行时间
    pub vruntime: u64,
    /// 上次开始计时的物理时间（ns）
    pub exec_start_ns: u64,
    /// 实际时间片（ns），0=未分配
    pub slice_ns: usize,
    /// 权重（由 nice 值决定）
    pub load: LoadWeight,

    // ---- EEVDF 专属 ----
    /// 虚拟截止时间 = vruntime + vslice；到达时续期并触发抢占
    pub deadline: u64,
    /// 积累的 lag = weight·(V - vruntime)，截断到 ±limit。
    /// 睡眠时保存，唤醒时 place_entity 用它恢复公平位置（关键！）
    pub vlag: i64,
    /// 上一次活跃周期的总 sum_exec（用于 lag_limit 计算）
    pub sum_exec_runtime: u64,
    /// 上次放入队列前的 sum_exec（用于 check_preempt_tick 的 delta_exec 计算）
    pub prev_sum_exec_runtime: u64,
}

impl SchedEntity {
    pub fn new(nice: i32) -> Self {
        Self {
            vruntime: 0,
            exec_start_ns: get_time_ns() as u64,
            slice_ns: 0,
            load: LoadWeight::from_nice(nice),
            deadline: 0,
            vlag: 0,
            sum_exec_runtime: 0,
            prev_sum_exec_runtime: 0,
        }
    }

    pub fn zero() -> Self {
        Self {
            vruntime: u64::MAX / 2,
            exec_start_ns: get_time_ns() as u64,
            slice_ns: 0,
            load: LoadWeight::zero(),
            deadline: u64::MAX / 2,
            vlag: 0,
            sum_exec_runtime: 0,
            prev_sum_exec_runtime: 0,
        }
    }

    /// 时钟中断：更新 vruntime 和 sum_exec
    pub fn update_vruntime(&mut self, now_ns: u64) {
        if now_ns <= self.exec_start_ns { return; }
        let delta_exec = now_ns - self.exec_start_ns;
        self.sum_exec_runtime = self.sum_exec_runtime.wrapping_add(delta_exec);
        self.vruntime = self.vruntime.wrapping_add(calc_delta_fair(delta_exec, &self.load));
        self.exec_start_ns = now_ns;
    }

    /// 计算 vslice = calc_delta_fair(slice_ns)
    #[inline]
    pub fn calc_vslice(&self, slice_ns: u64) -> u64 {
        calc_delta_fair(slice_ns, &self.load)
    }

    /// lag 截断上限（= vslice(max(1tick, 2×slice))，参考 Linux update_entity_lag）
    pub fn lag_limit(&self) -> i64 {
        let base = SCHED_LATENCY_NS.max(2 * self.slice_ns as u64);
        self.calc_vslice(base) as i64
    }
}

