    entity_slots:   BTreeMap<usize, EntitySlot>,
    next_seq:       u64, // FIFO 序列号：打破 vruntime 相等时的平局(替代 TID 次级键,避免大 tid 任务被饿死)

    // EEVDF V 增量维护（i128 防溢出，比 DragonOS i64 更保守安全）
    avg_vruntime: i128, // Σ scale_load(w_i)·(v_i - min_vruntime)
    avg_load:     i128, // Σ scale_load(w_i)

    curr:              Option<CurrInfo>,
    nr_running:        usize,
    min_vruntime:      u64,
    total_load_weight: u64,
}

impl EevdfScheduler {
    fn slot_is_queued(&self, tid: usize) -> bool {
        self.entity_slots
            .get(&tid)
            .map(|slot| self.tasks_timeline.contains_key(&(slot.vruntime, slot.seq)))
            .unwrap_or(false)
    }

    fn drop_stale_slot(&mut self, tid: usize) {
        let Some(slot) = self.entity_slots.remove(&tid) else {
            return;
        };
        self.tasks_timeline.remove(&(slot.vruntime, slot.seq));
        self.avg_sub(slot.vruntime, slot.weight);
        self.total_load_weight = self.total_load_weight.saturating_sub(slot.weight);
        self.nr_running = self.nr_running.saturating_sub(1);
    }

    pub fn new() -> Self {
        Self {
            tasks_timeline:    BTreeMap::new(),
            entity_slots:      BTreeMap::new(),
            next_seq:          0,
            avg_vruntime:      0,
            avg_load:          0,
            curr:              None,
            nr_running:        0,
            min_vruntime:      0,
            total_load_weight: 0,
        }
    }

    // ---- 内部数学工具 ----

    #[inline]
    fn scale_load(weight: u64) -> i128 { weight as i128 }

    #[inline]
    fn entity_key(&self, vruntime: u64) -> i128 {
        vruntime as i128 - self.min_vruntime as i128
    }

    /// 计算 V，含 curr 贡献（curr 不在队列，单独加入）。
    /// V = min_vr + (avg_vruntime + curr_key·curr_w) / (avg_load + curr_w)
    ///
    /// 向零截断修正（与 DragonOS avg_vruntime() line:753 一致）：
    ///   若 avg<0 则 avg = (avg - (load-1)) / load（等价于 ceil(avg/load) 朝零方向）
    pub fn avg_v(&self) -> u64 {
        let (mut avg, mut load) = (self.avg_vruntime, self.avg_load);
        if let Some(c) = &self.curr {
            let cw = Self::scale_load(c.weight);
            avg  += self.entity_key(c.vruntime) * cw;
            load += cw;
        }
        if load <= 0 { return self.min_vruntime; }
        let avg_div = if avg < 0 { (avg - (load - 1)) / load } else { avg / load };
        self.min_vruntime.wrapping_add(avg_div as u64)
    }

    /// entity_eligible 整数版（含 curr 贡献）：v_i ≤ V。
    /// 推导：(v_i - min_vr)·(load + curr_w) ≤ avg + curr_key·curr_w
    fn entity_eligible_full(&self, vruntime: u64) -> bool {
        let (mut avg, mut load) = (self.avg_vruntime, self.avg_load);
        if let Some(c) = &self.curr {
            let cw = Self::scale_load(c.weight);
            avg  += self.entity_key(c.vruntime) * cw;
            load += cw;
        }
        if load <= 0 { return true; }
        avg >= self.entity_key(vruntime) * load
    }

    fn avg_add(&mut self, vruntime: u64, weight: u64) {
        let w = Self::scale_load(weight);
        self.avg_vruntime += self.entity_key(vruntime) * w;
        self.avg_load     += w;
    }

    fn avg_sub(&mut self, vruntime: u64, weight: u64) {
        let w = Self::scale_load(weight);
        self.avg_vruntime -= self.entity_key(vruntime) * w;
        self.avg_load     -= w;
    }

    /// 推进 min_vruntime（不能回退），并修正 avg_vruntime（参考 DragonOS line:669）
    fn update_min_vruntime(&mut self) {
        let mut candidate = self.min_vruntime;

        // 队列中最小 vruntime
        if let Some((&(vr, _seq), _tid)) = self.tasks_timeline.iter().next() {
            candidate = candidate.max(vr);
        }

        // curr 的 vruntime（参与 min_vruntime 的计算，防止 min_vr 跳过 curr）
        if let Some(c) = &self.curr {
            candidate = candidate.min(c.vruntime);
        }

        if candidate > self.min_vruntime {
            let delta = candidate as i128 - self.min_vruntime as i128;
            // 每个 key 减少 delta，需要从 avg_vruntime 中减去 delta*avg_load
            self.avg_vruntime -= self.avg_load * delta;
            self.min_vruntime  = candidate;
        }
    }

    // ---- place_entity（带 lag 保留的入队定位）----

    /// 计算任务入队的正确 (vruntime, deadline)。
    ///
    /// - `is_initial=true`: 全新任务，vslice 减半防立即抢占。
    /// - 否则从 vlag 恢复：vruntime = V - lag_scaled；deadline = vruntime + vslice。
