/// Called during thread exit (CLONE_CHILD_CLEARTID): wake futex waiters on uaddr
/// using the exiting task's memory_set as the futex namespace.
/// Must be used instead of do_futex when cpu.current is already None.
pub fn futex_wake_from_task(task: &Arc<Task>, uaddr: usize, nr_waken: u32) -> isize {
    let page_mask = (1usize << 12) - 1;
    let offset = (uaddr & page_mask) as u32;
    let (token, mm_addr) = {
        let inner = task.inner.exclusive_access();
        (
            inner.get_user_token(),
            Arc::as_ptr(&inner.memory_set) as u64,
        )
    };

    // CLONE_CHILD_CLEARTID 的 tid futex 按 Linux ABI 约定是 **SHARED**：内核
    // mm_release 用不带 FUTEX_PRIVATE_FLAG 的 FUTEX_WAKE，glibc/musl 的
    // pthread_join 也据此用 shared 语义 futex_wait（key 用物理页，见 get_futex_key）。
    // 因此这里必须先按 shared key（物理页）唤醒；为兼容个别用 private 的实现，
    // 再用 private key（mm+虚拟页）补一次。两 key 可能 hash 到不同 bucket，分别加锁。
    let mut keys: alloc::vec::Vec<FutexKey> = alloc::vec::Vec::new();
    let pt = PageTable::from_token(token);
    if let Some(pa) = pt.translate_va(VirtAddr::from(uaddr)) {
        keys.push(FutexKey::new(0, (pa.0 & !page_mask) as u64, offset)); // shared（物理页）
    }
    keys.push(FutexKey::new(mm_addr, (uaddr & !page_mask) as u64, offset)); // private 兜底

    let mut woken = 0u32;
    for key in keys {
        if woken >= nr_waken {
            break;
        }
        let mut bucket = FUTEX_QUEUES.buckets[futex_hash(&key)].lock();
        bucket.retain(|fq| {
            if let Some(t) = fq.task.upgrade() {
                if woken < nr_waken && fq.key == key {
                    wake_futex_waiter(t);
                    woken += 1;
                    return false;
                }
                true
            } else {
                false
            }
        });
    }
    woken as isize
}

