impl BpfMapFile {
    fn new(attr: &BpfMapCreateAttr) -> Result<Self, isize> {
        let key_size = attr.key_size as usize;
        let value_size = attr.value_size as usize;
        let max_entries = attr.max_entries as usize;
        let _ = attr.map_flags;

        if key_size == 0
            || value_size == 0
            || max_entries == 0
            || key_size > MAX_KEY_SIZE
            || value_size > MAX_VALUE_SIZE
            || max_entries > MAX_ENTRIES
        {
            return Err(EINVAL);
        }

        let data = match attr.map_type {
            BPF_MAP_TYPE_HASH => BpfMapData::Hash(BTreeMap::new()),
            BPF_MAP_TYPE_ARRAY => {
                if key_size != core::mem::size_of::<u32>() {
                    return Err(EINVAL);
                }
                BpfMapData::Array(BTreeMap::new())
            }
            _ => return Err(EINVAL),
        };

        Ok(Self {
            map_type: attr.map_type,
            key_size,
            value_size,
            max_entries,
            inner: SpinNoIrqLock::new(BpfMapInner { data }),
        })
    }

    fn array_index(&self, key: &[u8]) -> Result<u32, isize> {
        if key.len() != core::mem::size_of::<u32>() {
            return Err(EINVAL);
        }
        let idx = read_u32(key, 0);
        if idx as usize >= self.max_entries {
            return Err(ENOENT);
        }
        Ok(idx)
    }

    fn lookup(&self, key: &[u8]) -> Result<Vec<u8>, isize> {
        let inner = self.inner.lock();
        match &inner.data {
            BpfMapData::Hash(map) => map.get(key).cloned().ok_or(ENOENT),
            BpfMapData::Array(map) => {
                let idx = self.array_index(key)?;
                Ok(map
                    .get(&idx)
                    .cloned()
                    .unwrap_or_else(|| vec![0u8; self.value_size]))
            }
        }
    }

    fn update(&self, key: Vec<u8>, value: Vec<u8>, flags: u64) -> isize {
        if flags != BPF_ANY && flags != BPF_NOEXIST && flags != BPF_EXIST {
            return EINVAL;
        }
        let mut inner = self.inner.lock();
        match &mut inner.data {
            BpfMapData::Hash(map) => {
                let exists = map.contains_key(&key);
                if flags == BPF_NOEXIST && exists {
                    return EEXIST;
                }
                if flags == BPF_EXIST && !exists {
                    return ENOENT;
                }
                if !exists && map.len() >= self.max_entries {
                    return E2BIG;
                }
                map.insert(key, value);
                0
            }
            BpfMapData::Array(map) => {
                if flags == BPF_NOEXIST {
                    return EINVAL;
                }
                let idx = match self.array_index(&key) {
                    Ok(idx) => idx,
                    Err(e) => return e,
                };
                map.insert(idx, value);
                0
            }
        }
    }

    fn delete(&self, key: &[u8]) -> isize {
        let mut inner = self.inner.lock();
        match &mut inner.data {
            BpfMapData::Hash(map) => {
