            BpfMapData::Array(_) => {
                let next = match key {
                    Some(prev) => self.array_index(prev)?.checked_add(1).ok_or(ENOENT)?,
                    None => 0,
                };
                if next as usize >= self.max_entries {
                    return Err(ENOENT);
                }
                Ok(next.to_le_bytes().to_vec())
            }
        }
    }
