/// 启动期注册架构计数器为系统 clocksource（boot 早期、跑用户态前调用一次）。
/// 各架构提供 `arch::get_time()`(原始 cycles) + `arch::clock_freq()`(Hz)。
pub fn init_clocksource() {
    clocksource::register(clocksource::ClockSource {
        name: if cfg!(target_arch = "riscv64") {
            "riscv-mtime"
        } else {
            "arch-counter"
        },
        rating: 300,
        freq_hz: clock_freq() as u64,
        read: || crate::arch::get_time() as u64,
    });
}

/// 读单调计数器原始 cycles（经选中 clocksource，未注册回退 arch 直读）。
pub fn get_time() -> usize {
    clocksource::read_cycles() as usize
}

pub fn get_time_ms() -> usize {
    (clocksource::cycles_to_ns(get_time() as u64) / (NSEC_PER_SEC / MSEC_PER_SEC) as u64) as usize
}

pub fn get_time_ns() -> usize {
    clocksource::cycles_to_ns(get_time() as u64) as usize
}

pub fn set_next_trigger() {
    set_timer(get_time() + clock_freq() / TICKS_PER_SEC);
}

/// 定时器 tick 的**架构无关**公共动作收口（仿 `arch::ipi::handle()` 模式）。
///
/// 两架构、用户态/内核态共 4 处 timer ISR 此前各自重复这三步（且 RV 两处误调
/// `check_timer` 两次=merge 残留多锁一次 TIMERS 堆）。统一为：
/// 1. `set_next_trigger`：one-shot 定时器重挂下一拍（RV/LA 硬件均为 one-shot 倒计时）；
/// 2. `check_timer`：排空到期定时器（nanosleep/POSIX timer/pipe-wait/select 注册的），
///    繁忙负载不进 idle 时若不在此排空，TIMERS 堆无限膨胀 → 内核堆耗尽 panic；
/// 3. `net::poll_interfaces`：虚拟 softirq 每拍推进协议栈（重入安全，POLL_GUARD 兜底）。
///
/// **抢占决策不在此**：RV 用户态走经典 tick 无条件 `set_need_resched`（cyclictest
/// stress 需要），LA 用户态走 `check_cfs_slice`（EEVDF 时间片）——蓄意差异，由各
/// arch ISR 在调用本函数后自行决定。内核态 timer 仅 idle WFI 唤醒来源、无任务可抢，
/// 两架构均不抢占（对称）。
///
/// x86/arm 接入：arch ISR = 「ack 定时器(arch 私有) → `on_timer_tick()` → 抢占策略」。
#[inline]
pub fn on_timer_tick() {
    set_next_trigger();
    check_timer();
    crate::net::poll_interfaces();
}

