/// 每 hart 专用「应急内核陷阱栈」字数（16KB）。内核栈溢出/sp 损坏时，__alltraps_k
/// 切到本栈保存上下文并打 KFAULT，而非在坏 sp 上 `sd` 触发静默陷阱风暴。
const KTRAP_STACK_WORDS: usize = 2048;
/// 栈最后一字预存 trap_from_kernel 指针（trampoline 无法 `la` 内核符号，只能
/// 经此间接拿到 handler）。其余字作为应急栈。每 hart 一份，互不干扰。
static mut KTRAP_STACKS: [[usize; KTRAP_STACK_WORDS]; crate::config::MAX_CPU_NUM] =
    [[0; KTRAP_STACK_WORDS]; crate::config::MAX_CPU_NUM];

pub fn init() {
    enable_user_time_counter();
    set_kernel_trap_entry();
}

fn enable_user_time_counter() {
    const SCOUNTEREN_TM: usize = 1 << 1;
    unsafe {
        asm!("csrs scounteren, {}", in(reg) SCOUNTEREN_TM);
    }
}

fn set_kernel_trap_entry() {
    extern "C" {
        fn __alltraps();
        fn __alltraps_k();
    }
    let __alltraps_k_va = __alltraps_k as usize - __alltraps as usize + TRAMPOLINE;
    let hart = crate::cpu::get_hartid();
    unsafe {
        // 应急栈顶 = 本 hart 数组最后一字的地址；该字写入 trap_from_kernel 指针。
        let top_slot = core::ptr::addr_of_mut!(KTRAP_STACKS[hart][KTRAP_STACK_WORDS - 1]);
        top_slot.write(trap_from_kernel as usize);
        stvec::write(__alltraps_k_va, TrapMode::Direct);
        sscratch::write(top_slot as usize);
    }
}

fn set_user_trap_entry() {
    unsafe {
        stvec::write(TRAMPOLINE as usize, TrapMode::Direct);
    }
}

