/// 发送 SIGSEGV；同一 stval 连续触发 ≥ 3 次且用户没装 handler 时改 SIGKILL 防无限循环。
/// 用户装了 SIGSEGV handler（如 lmbench lat_sig prot 的 prot()）的话，让用户自己处理，
/// 因为 handler 可能本来就是为了反复捕获 fault 做 trampoline 统计。
fn send_sigsegv_or_kill(task: &alloc::sync::Arc<crate::task::Task>, stval_val: usize) {
    use crate::signal::StellarSig;
    let mut inner = task.inner.exclusive_access();
    if inner.sigsegv_last_stval == stval_val {
        inner.sigsegv_repeat_count += 1;
    } else {
        inner.sigsegv_last_stval = stval_val;
        inner.sigsegv_repeat_count = 1;
    }
    let count = inner.sigsegv_repeat_count;
    let has_user_handler = inner
        .sig_handler
        .exclusive_access()
        .get(StellarSig::SIGSEGV)
        .is_user_handler();
    drop(inner);
    if count >= 3 && !has_user_handler {
        println!(
            "[kernel] SIGSEGV loop at {:#x} (count={}) without handler, sending SIGKILL.",
            stval_val, count
        );
        crate::signal::send_signal(task, StellarSig::SIGKILL);
    } else {
        crate::signal::send_signal(task, StellarSig::SIGSEGV);
    }
}

fn file_mmap_eof_fault(task: &alloc::sync::Arc<crate::task::Task>, addr: usize) -> bool {
    let vm = task.inner.exclusive_access().vm.clone();
    let fault = vm.exclusive_access().file_mmap_eof_fault(addr);
    fault
}

