/// 若当前任务的 ITIMER_REAL 已到期，则置 SIGALRM 为 pending。
///
/// 原本只在 `handle_signal()`（trap_return 路径）调用，但阻塞在内核
/// syscall 循环（如 socket send/recv 的 wq.wait）里的任务永远到不了
/// trap_return，SIGALRM 就永不产生（netperf -l N 的 send 循环因此死循环）。
/// 故抽成独立函数，阻塞 socket 循环被唤醒后也调用它。
///
/// 返回 true 表示本次调用实际把刚到期 itimer 转成了 SIGALRM 待处理
/// （Fresh expiry）。返回 false 表示没有新的 itimer 到期（可能还未到期，
/// 或已经在前一次调用中消耗完毕）。调用者可以据此区分"刚到期"和"已消费的
/// 过期信号"，避免后续控制通道 exchange 也被同一个 SIGALRM 误判 EINTR。
pub fn raise_expired_itimer() -> bool {
    if let Some(task) = current_task() {
        let mut inner = task.inner.exclusive_access();
        if inner.itimer_real_value_ms > 0 && !inner.sig_pending.contains(StellarSig::SIGALRM) {
            let elapsed = get_time_ms().saturating_sub(inner.itimer_real_start_ms);
            if elapsed >= inner.itimer_real_value_ms {
                inner.sig_pending.add(StellarSig::SIGALRM);
                if inner.itimer_real_interval_ms > 0 {
                    inner.itimer_real_value_ms = inner.itimer_real_interval_ms;
                    inner.itimer_real_start_ms = get_time_ms();
                } else {
                    inner.itimer_real_value_ms = 0;
                }
                return true;
            }
        }
    }
    false
}

