/// 延迟关闭列表：(handle, poll_count)。
/// 对端 FIN 可能在 close() 返回后才到达；socket 留在 SocketSet 直到
/// TimeWait/Closed，避免 listener 收到 stray FIN 后回 RST（TCP_CRR）。
/// 参考 Solaris: close() 立即返回，协议栈异步完成 FIN 握手 + 2MSL 清理。
static DEFERRED_CLOSES: Mutex<Vec<(SocketHandle, u32, bool)>> = Mutex::new(Vec::new());

/// 延迟关闭集合的内存安全上限。每个 TCP socket 携带 rx+tx 缓冲(~64KB×2)，
/// 优雅 teardown 把已关闭 socket 留在 SocketSet 等对端 FIN（256~1024 poll 轮）。
/// 正常 iperf/netperf/TCP_CRR 同时延迟关闭的 socket 屈指可数，但 connect02 等
/// 测例在紧循环里建/关 1000+ socket，远超清理速度 → 数千 × 128KB 堆积 → 128MB
/// 堆 OOM panic。超过上限时立即强制 remove 最旧的(释放缓冲)，把内存占用封顶在
/// ~16MB，仅在病态 churn 触发，不影响正常优雅关闭语义。
const MAX_DEFERRED_CLOSES: usize = 128;

/// 入队延迟关闭并强制内存上限：超限时强制移除最旧的 socket 释放其缓冲。
fn defer_close_push(handle: SocketHandle, fast_local: bool) {
    let mut list = DEFERRED_CLOSES.lock();
    if let Some((_, _, existing_fast)) = list.iter_mut().find(|(h, _, _)| *h == handle) {
        *existing_fast |= fast_local;
        return;
    }
    while list.len() >= MAX_DEFERRED_CLOSES {
        let (old, _, _) = list.remove(0);
        remove_socket(old);
    }
    list.push((handle, 0, fast_local));
}

struct FastTcpConn {
    client_ep: IpEndpoint,
    server_ep: IpEndpoint,
    c2s: Mutex<VecDeque<u8>>,
    s2c: Mutex<VecDeque<u8>>,
    client_closed: AtomicBool,
    server_closed: AtomicBool,
}

struct FastTcpSide {
    conn: Arc<FastTcpConn>,
    server: bool,
}

fn fast_peer_closed(side: &FastTcpSide) -> bool {
    if side.server {
        side.conn.client_closed.load(Ordering::Relaxed)
    } else {
        side.conn.server_closed.load(Ordering::Relaxed)
    }
}

